svg.script:
(function () {
  var svg = document.currentScript.ownerDocument.documentElement;

  var partConfig = {
    "main-rotor": {
      title: "Main Rotor",
      lines: [
        "The main rotor is the whole top spinning assembly.",
        "It creates most of the lift that raises the helicopter.",
        "It includes the hub and the rotor blades together.",
        "This system also helps the helicopter move in the air.",
        "Think of it as the helicopter's main lifting fan."
      ],
      targets: ["main-rotor", "hub", "rotor-blade-left", "rotor-blade-right", "pitch-link-left", "pitch-link-right"],
      fills: ["hub", "rotor-blade-left", "rotor-blade-right"],
      labels: ["label-main-rotor"]
    },
    "rotor-blade": {
      title: "Rotor Blade",
      lines: [
        "A rotor blade is one long airfoil attached to the hub.",
        "As it spins, it pushes air downward to help make lift.",
        "Each blade is only one part of the whole main rotor.",
        "Several blades together make the rotor system.",
        "This diagram highlights both blades for easy comparison."
      ],
      targets: ["rotor-blade-left", "rotor-blade-right"],
      fills: ["rotor-blade-left", "rotor-blade-right"],
      labels: ["label-rotor-blade"]
    },
    "hub": {
      title: "Hub",
      lines: [
        "The hub is the center part where rotor blades attach.",
        "It connects the blades to the mast and rotor controls.",
        "Forces from the spinning system pass through this point.",
        "It is the central joint of the main rotor.",
        "The hub helps hold the rotor assembly together."
      ],
      targets: ["hub"],
      fills: ["hub"],
      labels: ["label-hub"]
    },
    "mast": {
      title: "Mast",
      lines: [
        "The mast is the vertical shaft under the hub.",
        "It carries rotation upward into the main rotor system.",
        "The hub sits on top of the mast.",
        "Power reaches the mast through the transmission.",
        "It is a key link between the body and the rotor."
      ],
      targets: ["mast"],
      fills: ["mast"],
      labels: ["label-mast"]
    },
    "swashplate": {
      title: "Swashplate",
      lines: [
        "The swashplate helps change how the rotor blades tilt.",
        "That lets the helicopter move forward, backward, or sideways.",
        "It transfers pilot control inputs into rotor motion.",
        "This is one of the most important control parts.",
        "It helps change blade pitch while the rotor spins."
      ],
      targets: ["swashplate"],
      fills: ["swashplate"],
      labels: ["label-swashplate"]
    },
    "pitch-link": {
      title: "Pitch Link",
      lines: [
        "Pitch links connect the control system to the rotor head.",
        "They help change the angle, or pitch, of the blades.",
        "Changing pitch changes lift and direction of motion.",
        "These small links are important for precise control.",
        "They work with the swashplate near the hub."
      ],
      targets: ["pitch-link-left", "pitch-link-right"],
      fills: [],
      labels: ["label-pitch-link"]
    },
    "cockpit": {
      title: "Cockpit",
      lines: [
        "The cockpit is where the pilot sits and flies the helicopter.",
        "It contains the controls, instruments, and main flight view.",
        "This is the front working area of the aircraft.",
        "Pilots use it to steer, climb, and land safely.",
        "It is often covered by transparent windows."
      ],
      targets: ["cockpit"],
      fills: ["cockpit"],
      labels: ["label-cockpit"]
    },
    "engine": {
      title: "Engine",
      lines: [
        "The engine provides the power that turns the rotors.",
        "It creates mechanical energy for flight.",
        "That power is sent into the transmission system.",
        "Without engine power, the rotor system cannot spin normally.",
        "This drawing shows a simple engine compartment."
      ],
      targets: ["engine"],
      fills: ["engine"],
      labels: ["label-engine"]
    },
    "transmission": {
      title: "Transmission",
      lines: [
        "The transmission carries power from the engine to the rotors.",
        "It helps route power up to the mast and back to the tail rotor.",
        "This is part of the helicopter's drivetrain.",
        "It changes and transfers spinning force where needed.",
        "It is one reason the whole rotor system can work together."
      ],
      targets: ["transmission", "mast"],
      fills: ["transmission", "mast"],
      labels: ["label-transmission"]
    },
    "air-intake": {
      title: "Air Intake",
      lines: [
        "The air intake lets outside air enter the engine system.",
        "Engines need air so fuel can burn and make power.",
        "It is an important opening for airflow.",
        "The intake helps the engine breathe.",
        "Its exact shape depends on helicopter design."
      ],
      targets: ["air-intake"],
      fills: ["air-intake"],
      labels: ["label-air-intake"]
    },
    "exhaust": {
      title: "Exhaust",
      lines: [
        "The exhaust is where hot gases leave the engine.",
        "After fuel burns, the used gases must exit the aircraft.",
        "That is part of how the engine keeps running.",
        "Exhaust areas can become very hot.",
        "This part is often placed outside the cabin area."
      ],
      targets: ["exhaust"],
      fills: ["exhaust"],
      labels: ["label-exhaust"]
    },
    "fuselage": {
      title: "Fuselage",
      lines: [
        "The fuselage is the main body of the helicopter.",
        "It holds the cabin, cockpit, engine area, and structure.",
        "Many other parts connect to the fuselage.",
        "It is the central body shell of the aircraft.",
        "You can think of it as the helicopter's main frame."
      ],
      targets: ["fuselage"],
      fills: ["fuselage"],
      labels: ["label-fuselage"]
    },
    "landing-skids": {
      title: "Landing Skids",
      lines: [
        "Landing skids support the helicopter on the ground.",
        "They are used for landing, resting, and takeoff contact.",
        "Skids are simple and strong compared with wheels.",
        "They help spread the helicopter's weight.",
        "Many light helicopters use skids instead of landing gear wheels."
      ],
      targets: ["landing-skid-top", "landing-skid-bottom", "landing-skid-strut-left", "landing-skid-strut-right"],
      fills: [],
      labels: ["label-landing-skids"]
    },
    "tail-boom": {
      title: "Tail Boom",
      lines: [
        "The tail boom is the long rear section behind the fuselage.",
        "It holds the tail rotor far from the main body.",
        "That distance helps the tail rotor control yaw effectively.",
        "It is an important structural extension.",
        "It also supports tail fins and stabilizers."
      ],
      targets: ["tail-boom"],
      fills: ["tail-boom"],
      labels: ["label-tail-boom"]
    },
    "vertical-fin": {
      title: "Vertical Fin",
      lines: [
        "The vertical fin helps the helicopter stay directionally stable.",
        "It works a little like a weather vane in airflow.",
        "It can reduce side-to-side yaw disturbances.",
        "Some helicopters use it to support tail control.",
        "It is a fixed stabilizing surface near the tail."
      ],
      targets: ["vertical-fin"],
      fills: ["vertical-fin"],
      labels: ["label-vertical-fin"]
    },
    "horizontal-stabilizer": {
      title: "Horizontal Stabilizer",
      lines: [
        "The horizontal stabilizer helps balance the helicopter in forward flight.",
        "It can improve pitch stability.",
        "That helps the body stay better aligned as it moves ahead.",
        "It is a fixed aerodynamic surface on the tail.",
        "It supports smoother flight at speed."
      ],
      targets: ["horizontal-stabilizer"],
      fills: ["horizontal-stabilizer"],
      labels: ["label-horizontal-stabilizer"]
    },
    "tail-rotor": {
      title: "Tail Rotor",
      lines: [
        "The tail rotor helps control yaw, which turns the nose left or right.",
        "It counters the twisting force from the main rotor.",
        "Without it, the helicopter body would tend to spin.",
        "It is a key steering and balancing part.",
        "It is mounted at the end of the tail boom."
      ],
      targets: ["tail-rotor-group"],
      fills: [],
      labels: ["label-tail-rotor"]
    }
  };

  var allTargetIds = [
    "main-rotor",
    "hub",
    "mast",
    "swashplate",
    "pitch-link-left",
    "pitch-link-right",
    "rotor-blade-left",
    "rotor-blade-right",
    "cockpit",
    "engine",
    "transmission",
    "air-intake",
    "exhaust",
    "fuselage",
    "landing-skid-top",
    "landing-skid-bottom",
    "landing-skid-strut-left",
    "landing-skid-strut-right",
    "tail-boom",
    "vertical-fin",
    "horizontal-stabilizer",
    "tail-rotor-group"
  ];

  var allLabelIds = [
    "label-main-rotor",
    "label-mast",
    "label-hub",
    "label-rotor-blade",
    "label-swashplate",
    "label-pitch-link",
    "label-cockpit",
    "label-engine",
    "label-transmission",
    "label-air-intake",
    "label-exhaust",
    "label-fuselage",
    "label-landing-skids",
    "label-tail-boom",
    "label-vertical-fin",
    "label-horizontal-stabilizer",
    "label-tail-rotor"
  ];

  function byId(id) {
    return svg.getElementById(id);
  }

  function setInfo(title, lines) {
    byId("info-title").textContent = title;
    byId("info-line-1").textContent = lines[0] || "";
    byId("info-line-2").textContent = lines[1] || "";
    byId("info-line-3").textContent = lines[2] || "";
    byId("info-line-4").textContent = lines[3] || "";
    byId("info-line-5").textContent = lines[4] || "";
  }

  function clearState() {
    allTargetIds.forEach(function (id) {
      var el = byId(id);
      if (!el) return;
      el.classList.remove("active-stroke", "active-fill", "active-dashed", "dimmed");
    });

    allLabelIds.forEach(function (id) {
      var label = byId(id);
      if (label) label.classList.remove("label-active", "dimmed");
    });

    var tailGroup = byId("tail-rotor-group");
    if (tailGroup) {
      Array.prototype.forEach.call(tailGroup.querySelectorAll(".target"), function (node) {
        node.classList.remove("active-stroke", "dimmed");
      });
    }
  }

  function dimEverything() {
    allTargetIds.forEach(function (id) {
      var el = byId(id);
      if (el) el.classList.add("dimmed");
    });

    allLabelIds.forEach(function (id) {
      var label = byId(id);
      if (label) label.classList.add("dimmed");
    });

    var tailGroup = byId("tail-rotor-group");
    if (tailGroup) {
      Array.prototype.forEach.call(tailGroup.querySelectorAll(".target"), function (node) {
        node.classList.add("dimmed");
      });
    }
  }

  function activatePart(partName) {
    var cfg = partConfig[partName];
    if (!cfg) return;

    clearState();
    dimEverything();

    cfg.targets.forEach(function (id) {
      var el = byId(id);
      if (!el) return;

      el.classList.remove("dimmed");

      if (id === "main-rotor") {
        el.classList.add("active-dashed");
      } else if (id === "tail-rotor-group") {
        Array.prototype.forEach.call(el.querySelectorAll(".target"), function (node) {
          node.classList.remove("dimmed");
          node.classList.add("active-stroke");
        });
      } else {
        el.classList.add("active-stroke");
      }
    });

    cfg.fills.forEach(function (id) {
      var el = byId(id);
      if (el) el.classList.add("active-fill");
    });

    cfg.labels.forEach(function (id) {
      var el = byId(id);
      if (el) {
        el.classList.remove("dimmed");
        el.classList.add("label-active");
      }
    });

    setInfo(cfg.title, cfg.lines);
  }

  Array.prototype.forEach.call(svg.querySelectorAll("[data-part]"), function (node) {
    node.addEventListener("click", function () {
      activatePart(node.getAttribute("data-part"));
    });
  });

  activatePart("transmission");
})();
